use std::sync::{Arc, Mutex};

trait CachedBuilder {
    fn build(&self) -> Vec<i32>;
}

struct MyBuilder {
    cache: Arc<Mutex<Vec<i32>>>,
}

impl MyBuilder {
    fn new() -> Self {
        let vec = Vec::new();
        Self { cache: Arc::new(Mutex::new(vec)) }
    }
}

impl CachedBuilder for MyBuilder {
    fn build(&self) -> Vec<i32> {
        self.cache.lock().unwrap().clone()
    }
}

fn main() {
    let builder = MyBuilder::new(); // Initialize once
    println!("First build: {:?}", builder.build());
    println!("Second build: {:?}", builder.build());
}
